+    function finalizeOlderRenderJobs(currentRevision) {
+      for (const [revision, resolver] of pendingRenderJobs.entries()) {
+        if (revision >= currentRevision) {
+          continue;
+        }
+        resolver.resolve({ status: "superseded", revision });
+        pendingRenderJobs.delete(revision);
+      }
+    }
+
+    function scheduleRender(reason = "manual", { immediate = false } = {}) {
+      const revision = ++renderRevision;
+      const source = els.input.value;
+      const delay = immediate ? 0 : 220;
+      finalizeOlderRenderJobs(revision);
+
+      if (renderDebounceTimer) {
+        window.clearTimeout(renderDebounceTimer);
+      }
+
+      setRenderButtonState(true, delay > 0 ? "Queued" : "Rendering...");
+      els.parseSummary.textContent = delay > 0
+        ? `Queued ${reason} run · revision ${revision} · ${delay}ms debounce`
+        : `Starting ${reason} run · revision ${revision}`;
+      setChip(els.fmRenderChip, "queued", "border-cobalt/20 bg-cobalt/10 text-cobalt");
+      setChip(els.mermaidChip, "queued", "border-cobalt/20 bg-cobalt/10 text-cobalt");
+      setChip(els.canvasChip, "queued", "border-cobalt/20 bg-cobalt/10 text-cobalt");
+
+      const promise = new Promise((resolve, reject) => {
+        pendingRenderJobs.set(revision, { resolve, reject });
+      });
+
+      renderDebounceTimer = window.setTimeout(() => {
+        renderDebounceTimer = 0;
+        executeRenderPipeline(revision, source, reason);
+      }, delay);
+
+      return promise;
+    }
