+    async function measureStage(label, timings, fn) {
+      const start = performance.now();
+      try {
+        const value = await fn();
+        timings[label] = Math.round(performance.now() - start);
+        return value;
+      } catch (error) {
+        timings[label] = Math.round(performance.now() - start);
+        throw error;
+      }
+    }
